import React, { useState, useEffect } from "react";
import API from "../../api/api";
import Avatar from "../../components/common/Avatar";
import { socket } from "../../socket/socket";

export default function LeaderboardPage({ courseId }) {
  const [board, setBoard] = useState([]);

  useEffect(() => {
    if (!courseId) return;
    const fetchLB = async () => {
      try {
        const res = await API.get(`/dashboard/leaderboard/${courseId}`);
        setBoard(res.data);
      } catch (e) {
        console.error(e);
      }
    };
    fetchLB();
  }, [courseId]);

  useEffect(() => {
    const handler = (data) => {
       if (data.courseId === courseId) {
          setBoard(prev => {
             const exist = prev.find(p => p.user._id === data.userId);
             if (exist) {
                const updated = prev.map(p => p.user._id === data.userId ? {...p, progress: data.progress} : p);
                return updated.sort((a,b) => b.progress - a.progress).map((u, i) => ({...u, rank: i+1}));
             }
             return prev;
          });
       }
    };
    socket.on("progressUpdated", handler);
    return () => socket.off("progressUpdated", handler);
  }, [courseId]);

  return (
    <div className="page fade-up">
      <div className="mb-24">
        <div style={{ fontFamily: "var(--font-display)", fontSize: 26, fontWeight: 800, marginBottom: 4 }}>Leaderboard</div>
        <div style={{ color: "var(--text3)", fontSize: 14 }}>
          {courseId ? "Top performers in this course" : "Select a course to view leaderboard."}
        </div>
      </div>
      
      {board.length === 0 && courseId && <div className="card p-24" style={{padding: 24, fontSize: 13}}>No students have started this course yet.</div>}

      <div className="card">
        {board.map((s, i) => (
          <div key={s.rank} style={{ display: "flex", alignItems: "center", gap: 12, padding: "14px 20px", borderBottom: i < board.length - 1 ? "1px solid var(--border)" : "none" }}>
            <div className="rank-badge" style={{
                  background: i === 0 ? "var(--primary)" : i === 1 ? "var(--primary-light)" : i === 2 ? "var(--accent-light)" : "var(--surface)",
                  color: i === 0 ? "white" : i === 1 ? "var(--text)" : i === 2 ? "var(--accent)" : "var(--text-secondary)",
                  fontWeight: 500, fontSize: 12, border: "1px solid var(--border)", display: "flex", alignItems: "center", justifyContent: "center", width: 32, height: 32, borderRadius: "50%"
            }}>
              {i === 0 ? "1st" : i === 1 ? "2nd" : i === 2 ? "3rd" : `${s.rank}`}
            </div>
            <Avatar name={s.user?.name} color={"var(--primary)"} size={32} />
            <div style={{ flex: 1 }}>
               <div style={{ fontSize: 13, fontWeight: 600 }}>{s.user?.name}</div>
            </div>
            <div style={{ fontWeight: 700, fontSize: 13, color: "var(--primary)" }}>{s.progress}%</div>
          </div>
        ))}
      </div>
    </div>
  );
}
