import React, { useState, useEffect } from "react";
import API from "../../api/api";
import ProgressBar from "../../components/common/ProgressBar";
import Avatar from "../../components/common/Avatar";
import Tag from "../../components/common/Tag";

export default function InstructorDashboard({ user }) {
  const [courses, setCourses] = useState([]);
  const [totalCourses, setTotalCourses] = useState(0);
  const [totalStudents, setTotalStudents] = useState(0);

  const [activeCourseId, setActiveCourseId] = useState("");
  const [announceTitle, setAnnounceTitle] = useState("");
  const [announceMsg, setAnnounceMsg] = useState("");
  
  const [uploadFile, setUploadFile] = useState(null);
  const [uploadedUrl, setUploadedUrl] = useState("");
  const [uploading, setUploading] = useState(false);

  useEffect(() => {
    const fetchDashboard = async () => {
      try {
        const res = await API.get("/dashboard/instructor");
        setCourses(res.data.courses);
        setTotalCourses(res.data.totalCourses);
        setTotalStudents(res.data.totalStudents);
        if (res.data.courses.length > 0) setActiveCourseId(res.data.courses[0]._id);
      } catch (err) {
        console.error(err);
      }
    };
    fetchDashboard();
  }, []);

  const handleBroadcast = async () => {
     try {
        await API.post("/notifications/announce", { courseId: activeCourseId, title: announceTitle, message: announceMsg });
        alert("Broadcast sent successfully!");
        setAnnounceTitle("");
        setAnnounceMsg("");
     } catch (e) {
        console.log(e);
     }
  };

  const handleUpload = async () => {
     if (!uploadFile) return;
     setUploading(true);
     try {
        const fd = new FormData();
        fd.append("media", uploadFile);
        const res = await API.post("/upload", fd, { headers: { "Content-Type": "multipart/form-data" } });
        setUploadedUrl(`http://localhost:8000${res.data}`);
     } catch (e) {
        console.log(e);
     } finally {
        setUploading(false);
     }
  };

  return (
    <div className="page fade-up">
      <div className="mb-24">
        <div style={{ fontFamily: "var(--font-display)", fontSize: 26, fontWeight: 800, marginBottom: 4 }}>
          Instructor Panel
        </div>
        <div style={{ color: "var(--text3)", fontSize: 14 }}>Manage your courses and track student performance</div>
      </div>

      <div className="dashboard-grid">
        {[
          { icon: <svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="1.5"><path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20"></path><path d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z"></path></svg>, label: "Active Courses", value: totalCourses, sub: "currently teaching" },
          { icon: <svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="1.5"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"></path><circle cx="9" cy="7" r="4"></circle><path d="M23 21v-2a4 4 0 0 0-3-3.87"></path><path d="M16 3.13a4 4 0 0 1 0 7.75"></path></svg>, label: "Total Students", value: totalStudents, sub: "across all courses" },
          { icon: <svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="1.5"><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"></polyline></svg>, label: "Avg Completion", value: "0%", sub: "no data yet" },
          { icon: <svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="1.5"><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"></polygon></svg>, label: "Avg Rating", value: "0.0", sub: "no reviews" },
        ].map((s, i) => (
          <div key={i} className="stat-card card">
            <div className="stat-icon">{s.icon}</div>
            <div className="stat-label">{s.label}</div>
            <div className="stat-value">{s.value}</div>
            <div className="stat-sub">{s.sub}</div>
          </div>
        ))}
      </div>

      <div className="two-col mb-24">
        <div>
          <div className="section-header mb-16">
            <div><div className="section-title">Your Courses</div></div>
          </div>

          <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            {courses.length === 0 && <div className="card p-24" style={{padding: 24, fontSize: 13}}>No courses created yet.</div>}
            {courses.slice(0, 5).map(c => (
              <div key={c._id} className="card" style={{ padding: "16px 20px" }}>
                <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                  <div style={{ width: 40, height: 40, borderRadius: 10, background: "var(--surface2)", display: "flex", alignItems: "center", justifyContent: "center", overflow: "hidden" }}>
                    <img src={c.image} alt={c.title} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                  </div>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: 600, fontSize: 14 }}>{c.title}</div>
                    <div style={{ fontSize: 12, color: "var(--text3)", marginTop: 2 }}>{c.category} · ${c.price}</div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div style={{ display: "flex", flexDirection: "column", gap: 24 }}>
          {/* File Upload Studio */}
          <div>
            <div className="section-header mb-16">
              <div><div className="section-title">File Upload Studio</div></div>
            </div>
            <div className="card p-24" style={{padding: 24}}>
               <div style={{fontSize: 13, color: "var(--text-secondary)", marginBottom: 16}}>
                 Securely host course thumbnails, assignment PDFs, or MP4 lectures natively on the LMS server.
               </div>
               <div style={{display: 'flex', gap: 12}}>
                  <input type="file" className="form-input" onChange={e => setUploadFile(e.target.files[0])} style={{flex: 1}} />
                  <button className="btn btn-primary" onClick={handleUpload} disabled={uploading || !uploadFile}>
                    {uploading ? "Uploading..." : "Upload File"}
                  </button>
               </div>
               {uploadedUrl && (
                  <div style={{marginTop: 16, padding: 12, background: 'var(--surface2)', borderRadius: 8, fontSize: 13, wordBreak: 'break-all'}}>
                     <span style={{fontWeight: 600}}>Success! URL: </span>
                     <a href={uploadedUrl} target="_blank" rel="noreferrer" style={{color: 'var(--primary)'}}>{uploadedUrl}</a>
                     <div style={{marginTop: 4, color: 'var(--text3)'}}>Copy this URL into your Course configurations.</div>
                  </div>
               )}
            </div>
          </div>

          {/* Broadcast Announcement */}
          <div>
            <div className="section-header mb-16">
              <div><div className="section-title">Class Broadcast</div></div>
            </div>
            <div className="card p-24" style={{padding: 24}}>
               <select className="form-input mb-12" value={activeCourseId} onChange={e => setActiveCourseId(e.target.value)}>
                  {courses.map(c => <option key={c._id} value={c._id}>{c.title}</option>)}
               </select>
               <input className="form-input mb-12" placeholder="Announcement Title" value={announceTitle} onChange={e => setAnnounceTitle(e.target.value)} />
               <textarea className="form-input mb-12" placeholder="Write your message here..." rows={3} style={{resize: 'vertical'}} value={announceMsg} onChange={e => setAnnounceMsg(e.target.value)} />
               <div style={{display: 'flex', justifyContent: 'flex-end'}}>
                 <button className="btn btn-primary" disabled={!announceTitle || !announceMsg || !activeCourseId} onClick={handleBroadcast}>Send Push Notification</button>
               </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}